  7233 | OverflowResult llvm::computeOverflowForSignedMul(const Value *LHS,
  7234 |                                                  const Value *RHS,
  7235 |                                                  const SimplifyQuery &SQ) {
  7236 |   // Multiplying n * m significant bits yields a result of n + m significant
  7237 |   // bits. If the total number of significant bits does not exceed the
  7238 |   // result bit width (minus 1), there is no overflow.
  7239 |   // This means if we have enough leading sign bits in the operands
  7240 |   // we can guarantee that the result does not overflow.
  7241 |   // Ref: "Hacker's Delight" by Henry Warren
  7242 |   unsigned BitWidth = LHS->getType()->getScalarSizeInBits();
  7243 | 
  7244 |   // Note that underestimating the number of sign bits gives a more
  7245 |   // conservative answer.
  7246 |   unsigned SignBits =
  7247 |       ::ComputeNumSignBits(LHS, 0, SQ) + ::ComputeNumSignBits(RHS, 0, SQ);
  7248 | 
  7249 |   // First handle the easy case: if we have enough sign bits there's
  7250 |   // definitely no overflow.
  7251 |   if (SignBits > BitWidth + 1)
  7252 |     return OverflowResult::NeverOverflows;
  7253 | 
  7254 |   // There are two ambiguous cases where there can be no overflow:
  7255 |   //   SignBits == BitWidth + 1    and
  7256 |   //   SignBits == BitWidth
  7257 |   // The second case is difficult to check, therefore we only handle the
  7258 |   // first case.
  7259 |   if (SignBits == BitWidth + 1) {
  7260 |     // It overflows only when both arguments are negative and the true
  7261 |     // product is exactly the minimum negative number.
  7262 |     // E.g. mul i16 with 17 sign bits: 0xff00 * 0xff80 = 0x8000
  7263 |     // For simplicity we just check if at least one side is not negative.
  7264 |     KnownBits LHSKnown = computeKnownBits(LHS, /*Depth=*/0, SQ);
  7265 |     KnownBits RHSKnown = computeKnownBits(RHS, /*Depth=*/0, SQ);
  7266 |     if (LHSKnown.isNonNegative() || RHSKnown.isNonNegative())
  7267 |       return OverflowResult::NeverOverflows;
  7268 |   }
  7269 |   return OverflowResult::MayOverflow;
  7270 | }
