  7283 | static OverflowResult
  7284 | computeOverflowForSignedAdd(const WithCache<const Value *> &LHS,
  7285 |                             const WithCache<const Value *> &RHS,
  7286 |                             const AddOperator *Add, const SimplifyQuery &SQ) {
  7287 |   if (Add && Add->hasNoSignedWrap()) {
  7288 |     return OverflowResult::NeverOverflows;
  7289 |   }
  7290 | 
  7291 |   // If LHS and RHS each have at least two sign bits, the addition will look
  7292 |   // like
  7293 |   //
  7294 |   // XX..... +
  7295 |   // YY.....
  7296 |   //
  7297 |   // If the carry into the most significant position is 0, X and Y can't both
  7298 |   // be 1 and therefore the carry out of the addition is also 0.
  7299 |   //
  7300 |   // If the carry into the most significant position is 1, X and Y can't both
  7301 |   // be 0 and therefore the carry out of the addition is also 1.
  7302 |   //
  7303 |   // Since the carry into the most significant position is always equal to
  7304 |   // the carry out of the addition, there is no signed overflow.
  7305 |   if (::ComputeNumSignBits(LHS, 0, SQ) > 1 &&
  7306 |       ::ComputeNumSignBits(RHS, 0, SQ) > 1)
  7307 |     return OverflowResult::NeverOverflows;
  7308 | 
  7309 |   ConstantRange LHSRange =
  7310 |       computeConstantRangeIncludingKnownBits(LHS, /*ForSigned=*/true, SQ);
  7311 |   ConstantRange RHSRange =
  7312 |       computeConstantRangeIncludingKnownBits(RHS, /*ForSigned=*/true, SQ);
  7313 |   OverflowResult OR =
  7314 |       mapOverflowResult(LHSRange.signedAddMayOverflow(RHSRange));
  7315 |   if (OR != OverflowResult::MayOverflow)
  7316 |     return OR;
  7317 | 
  7318 |   // The remaining code needs Add to be available. Early returns if not so.
  7319 |   if (!Add)
  7320 |     return OverflowResult::MayOverflow;
  7321 | 
  7322 |   // If the sign of Add is the same as at least one of the operands, this add
  7323 |   // CANNOT overflow. If this can be determined from the known bits of the
  7324 |   // operands the above signedAddMayOverflow() check will have already done so.
  7325 |   // The only other way to improve on the known bits is from an assumption, so
  7326 |   // call computeKnownBitsFromContext() directly.
  7327 |   bool LHSOrRHSKnownNonNegative =
  7328 |       (LHSRange.isAllNonNegative() || RHSRange.isAllNonNegative());
  7329 |   bool LHSOrRHSKnownNegative =
  7330 |       (LHSRange.isAllNegative() || RHSRange.isAllNegative());
  7331 |   if (LHSOrRHSKnownNonNegative || LHSOrRHSKnownNegative) {
  7332 |     KnownBits AddKnown(LHSRange.getBitWidth());
  7333 |     computeKnownBitsFromContext(Add, AddKnown, /*Depth=*/0, SQ);
  7334 |     if ((AddKnown.isNonNegative() && LHSOrRHSKnownNonNegative) ||
  7335 |         (AddKnown.isNegative() && LHSOrRHSKnownNegative))
  7336 |       return OverflowResult::NeverOverflows;
  7337 |   }
  7338 | 
  7339 |   return OverflowResult::MayOverflow;
  7340 | }
