new='''bool llvm::isKnownNonEqual(const Value *V1, const Value *V2,
                           const SimplifyQuery &Q, unsigned Depth) {
  // We don't support looking through casts.
  if (V1 == V2 || V1->getType() != V2->getType())
    return false;

  if (Q.CxtI && Q.DC && Q.DT) {
    auto ImpliedByCond = [&](BranchInst *BI, bool IsTrueDest) {
      if (!BI)
        return false;
      BasicBlockEdge Edge(BI->getParent(), BI->getSuccessor(IsTrueDest ? 0 : 1));
      if (!Q.DT->dominates(Edge, Q.CxtI->getParent()))
        return false;

      auto *Cmp = dyn_cast<ICmpInst>(BI->getCondition());
      if (!Cmp)
        return false;

      ICmpInst::Predicate Pred = IsTrueDest ? Cmp->getPredicate()
                                            : Cmp->getInversePredicate();
      return Pred == ICmpInst::ICMP_NE &&
             ((Cmp->getOperand(0) == V1 && Cmp->getOperand(1) == V2) ||
              (Cmp->getOperand(0) == V2 && Cmp->getOperand(1) == V1));
    };

    for (BranchInst *BI : Q.DC->conditionsFor(V1))
      if (ImpliedByCond(BI, true) || ImpliedByCond(BI, false))
        return true;
  }

  auto *FVTy = dyn_cast<FixedVectorType>(V1->getType());
  APInt DemandedElts =
      FVTy ? APInt::getAllOnes(FVTy->getNumElements()) : APInt(1, 1);
  return ::isKnownNonEqual(V1, V2, DemandedElts, Depth, Q);
}
